import type {
  EngineAdapter,
  EngineAdapterOptions,
  EventBridgeFn,
  PlayerSource,
} from '@tanstack-player/core'
import { PlayerEvent } from '@tanstack-player/core'

/**
 * Video.js engine adapter.
 * Bridges the TanStack Player controller ↔ Video.js player instance.
 */
export class VideoJsAdapter implements EngineAdapter {
  private player: any = null
  private bridge: EventBridgeFn | null = null
  private videoElement: HTMLVideoElement | null = null

  setEventBridge(bridge: EventBridgeFn): void {
    this.bridge = bridge
  }

  init(container: HTMLElement, options: EngineAdapterOptions): void {
    // Video.js is expected to be available globally (loaded via CDN or bundled)
    const vjsFn = (globalThis as any).videojs
    if (!vjsFn) {
      throw new Error(
        '[TanStack Player] Video.js not found. Please load video.js via CDN or import it in your bundle.'
      )
    }

    // Create the <video> element
    this.videoElement = document.createElement('video')
    this.videoElement.className = 'video-js vjs-big-play-centered'
    container.appendChild(this.videoElement)

    // Normalize source
    const sources = this.normalizeSources(options.src)

    // Build Video.js options
    const vjsOptions: Record<string, any> = {
      controls: options.controls ?? true,
      autoplay: options.autoPlay ?? false,
      preload: options.preload ?? 'auto',
      fluid: options.fluid ?? true,
      sources,
      ...(options.engineOptions ?? {}),
    }

    if (options.playbackRates) {
      vjsOptions.playbackRates = options.playbackRates
    }

    // Initialize Video.js player
    this.player = vjsFn(this.videoElement, vjsOptions, () => {
      this.emitBridge(PlayerEvent.READY)
    })

    this.bindEvents()
  }

  play(): void {
    this.player?.play()?.catch?.(() => {
      // Autoplay may be blocked by browser
    })
  }

  pause(): void {
    this.player?.pause()
  }

  seek(seconds: number): void {
    if (this.player) {
      this.player.currentTime(seconds)
    }
  }

  setVolume(value: number): void {
    if (this.player) {
      this.player.volume(value)
    }
  }

  setMuted(muted: boolean): void {
    if (this.player) {
      this.player.muted(muted)
    }
  }

  setPlaybackRate(rate: number): void {
    if (this.player) {
      this.player.playbackRate(rate)
    }
  }

  requestFullscreen(): void {
    this.player?.requestFullscreen()
  }

  exitFullscreen(): void {
    this.player?.exitFullscreen()
  }

  loadSource(src: PlayerSource | PlayerSource[]): void {
    if (!this.player) return
    const sources = this.normalizeSources(src)
    this.player.src(sources)
  }

  getCurrentTime(): number {
    return this.player?.currentTime() ?? 0
  }

  getDuration(): number {
    return this.player?.duration() ?? 0
  }

  getVolume(): number {
    return this.player?.volume() ?? 1
  }

  getPlaybackRate(): number {
    return this.player?.playbackRate() ?? 1
  }

  isFullscreen(): boolean {
    return this.player?.isFullscreen() ?? false
  }

  destroy(): void {
    if (this.player) {
      this.player.dispose()
      this.player = null
    }
    this.videoElement = null
    this.bridge = null
  }

  // ─── Internal ───────────────────────────────────────────

  private bindEvents(): void {
    if (!this.player) return

    this.player.on('play', () => {
      this.emitBridge(PlayerEvent.PLAY)
    })

    this.player.on('pause', () => {
      this.emitBridge(PlayerEvent.PAUSE)
    })

    this.player.on('timeupdate', () => {
      this.emitBridge(PlayerEvent.TIME_UPDATE, {
        currentTime: this.player.currentTime(),
        duration: this.player.duration() || 0,
      })
    })

    this.player.on('loadedmetadata', () => {
      this.emitBridge(PlayerEvent.LOADED_METADATA, {
        duration: this.player.duration(),
      })
    })

    this.player.on('ended', () => {
      this.emitBridge(PlayerEvent.ENDED)
    })

    this.player.on('volumechange', () => {
      this.emitBridge(PlayerEvent.VOLUME_CHANGE, {
        volume: this.player.volume(),
        muted: this.player.muted(),
      })
    })

    this.player.on('ratechange', () => {
      this.emitBridge(PlayerEvent.RATE_CHANGE, {
        rate: this.player.playbackRate(),
      })
    })

    this.player.on('fullscreenchange', () => {
      this.emitBridge(PlayerEvent.FULLSCREEN_CHANGE, {
        isFullscreen: this.player.isFullscreen(),
      })
    })

    this.player.on('progress', () => {
      const buffered = this.player.bufferedPercent() ?? 0
      this.emitBridge(PlayerEvent.BUFFER, { buffered })
    })

    this.player.on('error', () => {
      const err = this.player.error()
      this.emitBridge(PlayerEvent.ERROR, {
        error: new Error(err?.message ?? 'Unknown player error'),
      })
    })
  }

  private emitBridge(event: string, data?: any): void {
    this.bridge?.(event, data)
  }

  private normalizeSources(
    src: PlayerSource | PlayerSource[]
  ): Array<{ src: string; type: string }> {
    const sources = Array.isArray(src) ? src : [src]
    return sources.map((s) => ({
      src: s.src,
      type: s.type ?? this.inferType(s.src),
    }))
  }

  private inferType(src: string): string {
    if (src.endsWith('.m3u8')) return 'application/x-mpegURL'
    if (src.endsWith('.mpd')) return 'application/dash+xml'
    if (src.endsWith('.webm')) return 'video/webm'
    if (src.endsWith('.ogg') || src.endsWith('.ogv')) return 'video/ogg'
    return 'video/mp4'
  }
}

/**
 * Factory function for creating a Video.js adapter.
 */
export function createVideoJsAdapter(): VideoJsAdapter {
  return new VideoJsAdapter()
}
